// KubeVirt VMI CPU Metrics
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("kubevirt.thanos.host")
def token = hostProps.get("kubevirt.thanos.token")
def vmiName = instanceProps.get("wildvalue")

if (!host || !token || !vmiName) {
    println("cpu_usage_seconds:0")
    println("cpu_system_seconds:0")
    println("cpu_user_seconds:0")
    println("vcpu_seconds:0")
    println("vcpu_wait:0")
    println("vcpu_delay:0")
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def baseUrl = "https://${host}:443"

def cpuUsage = 0
def cpuSystem = 0
def cpuUser = 0
def vcpuSec = 0
def vcpuWait = 0
def vcpuDelay = 0

try {
    // CPU Usage
    def query = "rate(kubevirt_vmi_cpu_usage_seconds_total{name=\"${vmiName}\"}[5m])"
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)
    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)
        if (json.status == "success" && json.data?.result?.size() > 0) {
            cpuUsage = (json.data.result[0].value[1] as Double) * 100
        }
    }
} catch (Exception e) {}

try {
    // CPU System
    def query = "rate(kubevirt_vmi_cpu_system_usage_seconds_total{name=\"${vmiName}\"}[5m])"
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)
    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)
        if (json.status == "success" && json.data?.result?.size() > 0) {
            cpuSystem = (json.data.result[0].value[1] as Double) * 100
        }
    }
} catch (Exception e) {}

try {
    // CPU User
    def query = "rate(kubevirt_vmi_cpu_user_usage_seconds_total{name=\"${vmiName}\"}[5m])"
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)
    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)
        if (json.status == "success" && json.data?.result?.size() > 0) {
            cpuUser = (json.data.result[0].value[1] as Double) * 100
        }
    }
} catch (Exception e) {}

try {
    // vCPU Seconds
    def query = "sum(rate(kubevirt_vmi_vcpu_seconds_total{name=\"${vmiName}\"}[5m]))"
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)
    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)
        if (json.status == "success" && json.data?.result?.size() > 0) {
            vcpuSec = (json.data.result[0].value[1] as Double) * 100
        }
    }
} catch (Exception e) {}

try {
    // vCPU Wait
    def query = "sum(rate(kubevirt_vmi_vcpu_wait_seconds_total{name=\"${vmiName}\"}[5m]))"
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)
    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)
        if (json.status == "success" && json.data?.result?.size() > 0) {
            vcpuWait = (json.data.result[0].value[1] as Double) * 100
        }
    }
} catch (Exception e) {}

try {
    // vCPU Delay
    def query = "sum(rate(kubevirt_vmi_vcpu_delay_seconds_total{name=\"${vmiName}\"}[5m]))"
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)
    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)
        if (json.status == "success" && json.data?.result?.size() > 0) {
            vcpuDelay = (json.data.result[0].value[1] as Double) * 100
        }
    }
} catch (Exception e) {}

println("cpu_usage_seconds:" + cpuUsage)
println("cpu_system_seconds:" + cpuSystem)
println("cpu_user_seconds:" + cpuUser)
println("vcpu_seconds:" + vcpuSec)
println("vcpu_wait:" + vcpuWait)
println("vcpu_delay:" + vcpuDelay)

return 0
